package com.mobiquel.udhampur.dbadapter;import android.content.Context;import android.database.SQLException;import android.database.sqlite.SQLiteDatabase;import com.readystatesoftware.sqliteasset.SQLiteAssetHelper;public class DBAdapter extends SQLiteAssetHelper {	private static String DB_NAME = "udhampur.db";	private SQLiteDatabase myDataBase;	public static final String ISSUE_LIST_TABLE = "issueList";		private static int DB_VERSION = 1;		public DBAdapter(Context context)     {    	super(context, DB_NAME, null, DB_VERSION);    }	     public SQLiteDatabase openDataBase() throws SQLException    {    	myDataBase = getWritableDatabase();    	return myDataBase;    }     @Override	public synchronized void close()     {    	if(myDataBase != null)    		myDataBase.close();    	    super.close();	}}